	.SBTTL	ICOMACRO; Gestion des macros; ------------------;---------\\; COPMACRO >;=========/; Excute une macro qui n'est pas dans OBUEXE.; in	A3.L	^macro  excuter; out	D7.W	erreur; mod	D7.WCOPMACRO:	PUSHM.L	A3,A4	LOAD.L	A4,#(A6)+OBUEXE10$:	LOAD.B	(A4+),(A3+)	JUMP,NE	10$	CALL	EXMACRO	POPM.L	A3,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; EXMACRO >;========/; in	-; out	D7.W	erreur; mod	D7.WEXMACRO:	PUSHM.L	D3,A0,A3,A4	LOAD.W	D7,#ERILOP	TEST.B	(A6)+OFLAGM:#BMACRO ; macro dj en excution ?	JUMP,BS	90$		; oui => 90$	CALL	OPZMAC		; A0 <-- ^variables macro	JUMP,NE	90$	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^nom termin par .CLE	LOAD.L	A4,#(A0)+OLIMAC10$:	LOAD.B	(A4+),(A3+)	; OLIMAC <-- ligne macro	JUMP,NE 10$	LOAD.L	A3,#(A0)+OLIMAC	; A3 <-- ^dbut ligne	LOAD.L	A4,A3		; A4 <-- ^dbut ligne	LOAD.B	D3,#2^BOPRD	FOS	?OPEN		; ouvre le fichier macro	JUMP',NE 90$	LOAD.W	(A0)+OCHMAC,D6	; mm canal fichier macro	LOAD.W	(A0)+OLGMAC,#LGBLK	LOAD.W	(A0)+OPTMAC,#LGBLK	TSET.B	(A6)+OFLAGM:#BMACRO ; signal macro en excution	TCLR.B	(A6)+OFLAGM:#BMNOAF ; affiche la macro90$:	POPM.L	D3,A0,A3,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; GETMACRO >;=========/; Lit une ligne dans le fichier macro.; Cette routine simule exactement GETLINE.; in	-; out	A3.L	^ligne de commande lue;	D7.W	erreur; mod	D7.W, A3.LGETMACRO:	PUSHM.L	D3,D4,D6	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^buffer pour ligne	CLR.W	D4		; D4 <-- nb caractres20$:	COMP.W	D4,#LBUEXE-2	JUMP',HS 50$	CALL	RDONEM		; D3 <-- un caractre	JUMP,NE 80$	COMP.B	D3,#H'80	; caractre > H'80 ?	JUMP,HS 20$		; oui => ignore-le	COMP.B	D3,#CR		; fin de la ligne ?	JUMP',EQ 50$		; oui => 50$	LOAD.B	(A3+),D3	INC.W	D4	COMP.B	D3,#SPACE	JUMP,NE	20$	LOAD.B	(A3+),#CARMARK	INC.W	D4	JUMP	20$50$:	CLR.B	(A3)		; termine ligne par <0>	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^ligne commande lue	TEST.B	(A3)		; ligne vide ?	JUMP,EQ 20$		; oui => lit une autre ligne	CALL	IPMACRO		; insre le(s) paramtre(s)	TEST.B	(A6)+OFLAGM:#BMNOAF ; affiche la macro ?	JUMP',BS 70$		; non => 70$	CALL	AFCOMM		; oui => affiche la ligne	LOAD.B	D3,#NOCURS	LIB	?AFCAR		; plus de curseur70$:	CLR.W	D7		; D7 <-- ok	JUMP'	90$80$:	CALL	ENDMACRO	; stoppe la macro90$:	POPM.L	D3,D4,D6	TEST.W	D7		; retour EQ/NE	RET;--------\; IPMACRO >;========/; Ajoute dans une ligne de commande le ou les paramtres; signals par %n.;	$0..$9	paramtres sur la ligne de commande;	$L	langue parle dans le systme; in	A3.L	^ligne de commande; out	-; mod	-IPMACRO:	PUSHM.L	D0,D3,A0,A1,A2,A3,A4,A5	LOAD.L	A0,(A6)+OZOMAC	; A0 <-- ^variables macro	LOAD.L	A4,A3		; A4 <-- ^dans commande	LOAD.L	A2,A3		; A2 <-- ^dbut commande10$:	LOAD.B	D3,(A4+)	JUMP,EQ 90$	COMP.B	D3,#'%		; demande d'un paramtre ?	JUMP,NE 10$		; non => 10$				; oui =>	LOAD.B	D3,(A4+)	; D3 <-- chiffre aprs "n"	LIB	?MINMAJ	COMP.B	D3,#'L		; "%L" ?	JUMP,EQ	70$		; oui => 70$	COMP.B	D3,#'0	JUMP,LO 10$	COMP.B	D3,#'9		; "%0..%9" ?	JUMP,HI 10$		; non => 10$	LOAD.B	D0,D3	SUB.B	D0,#'0		; D0 <-- 0..9	LOAD.L	A3,#(A0)+OLIMAC	; A3 <-- ^nom fichier macro +30$:	TEST.B	D0	JUMP',EQ 40$	DEC.B	D0	CALL	SKPNAM		; A3 <-- ^paramtre suivant	JUMP	30$40$:	LOAD.L	A5,#(A0)+OPAMAC50$:	LOAD.B	D3,(A3+)	JUMP',EQ 55$	COMP.B	D3,#SPACE	JUMP',EQ 55$	LOAD.B	(A5+),D3	; OPAMAC <-- paramtre	JUMP	50$55$:	CLR.B	(A5)		; termine le paramtre	LOAD.L	A5,#(A0)+OPAMAC	; A5 <-- ^paramtre  insrer60$:	LOAD.L	A1,A4	SUB.L	A4,#2		; A4 <-- ^caractres %n	PUSH.L	A462$:	LOAD.B	(A4+),(A1+)	; supprime %n	JUMP,NE 62$	POP.L	A4	LOAD.B	D3,(A5)		; D3 <-- 1er car paramtre	JUMP,EQ 10$		; paramtre inexistant => 10$				; non =>	LOAD.L	A3,A2		; A3 <-- ^dbut ligne	LOAD.L	D3,#LBUEXE	LIB	?INSERT		; insre le paramtre	JUMP	10$70$:	LOAD.L	A5,#(A0)+OPAMAC	; A5 <-- ^paramtre  insrer	LIB	?GETLAN		; D3 <-- langue (F,E,D,I)	LOAD.B	(A5)+0,D3	; met langue	CLR.B	(A5)+1		; met terminateur	JUMP	60$		; insre dans ligne de commande90$:	POPM.L	D0,D3,A0,A1,A2,A3,A4,A5	RET;--------\; RDONEM  >;--------/; Lit un byte dans le fichier macro.; in	-; out	D3.B	caractre;	D7.W	erreur; mod	D3.B, D7.WRDONEM:	PUSHM.L	D4,D6,A0,A4	LOAD.L	A0,(A6)+OZOMAC	; A0 <-- ^variables macro10$:	LOAD.W	D4,(A0)+OPTMAC	; D4 <-- ^relatif dans OBUMAC	COMP.W	D4,(A0)+OLGMAC	JUMP',HS 20$	LOAD.L	A4,#(A0)+OBUMAC	LOAD.B	D3,(A4)+(D4.W)	INC.W	(A0)+OPTMAC	; avance le ^relatif	CLR.W	D7		; D7 <-- ok	JUMP'	90$20$:	CLR.W	(A0)+OPTMAC	; clear le ^relatif	LOAD.L	A4,#(A0)+OBUMAC	; A4 <-- ^buffer pour un bloc	LOAD.L	D4,#LGBLK	; D4 <-- longueur d'un bloc	LOAD.W	D6,(A0)+OCHMAC	; D6 <-- canal fichier macro	FOS	?RDBYTE		; lit 256 caractres	LOAD.W	(A0)+OLGMAC,D4	; init lg lue (0..256)	TEST.W	D7		; erreur ?	JUMP,EQ 10$		; non => 10$	COMP.W	D7,#EROUTF	; "out of file" ?	JUMP',NE 90$		; non => 90$	TEST.W	D4		; lg lue = zro ?	JUMP,NE 10$		; non => 10$90$:	POPM.L	D4,D6,A0,A4	TEST.W	D7		; retour EQ/NE	RET;---------\; ENDMACRO >;=========/; Stoppe l'ventuelle macro en cours.; in	-; out	-; mod	- (surtout pas D7.W)ENDMACRO:	PUSHM.L	D1,D6,D7,A0,A4	LOAD.L	A0,(A6)+OZOMAC	; A0 <-- ^variables macro	TEST.B	(A6)+OFLAGM:#BMACRO ; macro en excution ?	JUMP',BC 90$		; non => 90$				; oui =>	LOAD.W	D6,(A0)+OCHMAC	; A0 <-- canal fichier macro	FOS	?CLOSE		; ferme le fichier macro	CALL	CLZMAC		; rend les variables macro	TCLR.B	(A6)+OFLAGM:#BMACRO ; signal macro termine	LOAD.L	A4,(A6)+OPTDEF	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM		; libre ICONE.LIST	CALL	INIDEF		; relit ICONE.LIST90$:	POPM.L	D1,D6,D7,A0,A4	RET;--------\; OPZMAC  >;--------/; Prend une zone mmoire pour les macros.; in	-; out	A0.L	^zone mmoire;	D7.W	erreur; mod	D7.W, A0.LOPZMAC:	PUSHM.L	D1,D4,A4	LOAD.L	D4,#LGZMAC	; D4 <-- lg zone	LOAD.W	D1,#MTYPCP	GESMEM	?GETMEM		; demande zone pour macro	JUMP',NE 90$	LOAD.L	(A6)+OZOMAC,A4	LOAD.L	A0,A4		; A0 <-- ^zone90$:	POPM.L	D1,D4,A4	TEST.W	D7		; retour EQ/NE	RET;--------\; CLZMAC  >;--------/; Libre la zone mmoire pour les macros.; in	-; out	-; mod	-CLZMAC:	PUSHM.L	D1,D7,A4	TEST.L	(A6)+OZOMAC	; zone mmoire existe ?	JUMP',EQ 90$		; non => 90$				; oui =>	LOAD.L	A4,(A6)+OZOMAC	; A4 <-- ^zone mmoire	LOAD.W	D1,#MTYPCP	GESMEM	?GIVMEM		; rend zone pour macro	CLR.L	(A6)+OZOMAC	; signal zone rendue90$:	POPM.L	D1,D7,A4	RET	.END